wrong_code:
// WRONG — invented selector 0x4e6c8f80 does not match keccak256("NotOwner()")[0:4]
// Also wrong: contract never declares 'error NotOwner()' so ABI decoders cannot decode it
mstore(0x00, 0x4e6c8f80)
revert(0x1c, 0x04)

correct_code:
// CORRECT — use the canonical selector from the Gaslite error table
// NotOwner() = first 4 bytes of keccak256("NotOwner()") = 0x30cd7471
mstore(0x00, 0x30cd7471)
revert(0x1c, 0x04)
